// ── Flatten and validate ──
const allQuestions = [];
const allRefs = new Set();
const seenIds = new Set();

for (const cat of categories) {
  for (const q of cat.questions) {
    if (seenIds.has(q.id)) {
      console.error(`DUPLICATE ID: ${q.id}`);
      process.exit(1);
    }
    seenIds.add(q.id);

    for (const ref of q.refs) {
      if (allRefs.has(ref)) {
        console.error(`DUPLICATE VERSE: ${ref} in question ${q.id}`);
        process.exit(1);
      }
      allRefs.add(ref);
    }

    allQuestions.push({
      id: q.id,
      family: cat.category,
      prompt: q.prompt,
      expectedPolicy: "survey_bundle",
      expectedReliable: true,
      expectedPrimaryRefs: q.refs,
      minSupportingCount: 2,
      expectedSafetyLevel: "none",
      expectedEvidenceTerms: q.terms,
      minEvidenceTermHits: 2,
      forbiddenPhrases: ["더 구체적인 연결이 필요", "낮은 신뢰도", "확정하지", "본문 단어가 충분하지 않습니다"],
      maxLatencyMs: 4000,
    });
  }
}

console.log(`Total questions: ${allQuestions.length}`);
console.log(`Total unique verses: ${allRefs.size}`);
console.log(`Categories: ${categories.length}`);

// Verify no duplicate verses
const refList = [...allRefs];
const refSet = new Set(refList);
if (refList.length !== refSet.size) {
  console.error("ERROR: Duplicate verses found!");
  process.exit(1);
}

// Write JSON
const outPath = path.join(process.cwd(), 'qa', 'philosophical-deep-qa.json');
writeFileSync(outPath, JSON.stringify(allQuestions, null, 2), 'utf8');
console.log(`Written to ${outPath}`);
